# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import NoBrokersAvailable, TopicAlreadyExistsError, UnknownTopicOrPartitionError

def create_topic(admin_client, topic_name, num_partitions, replication_factor, topic_configs):
    print(f"Attempting to create topic: {topic_name}")
    print(f"  Partitions: {num_partitions}")
    print(f"  Replication Factor: {replication_factor}")
    print(f"  Configs: {topic_configs}")

    new_topic = NewTopic(
        name=topic_name,
        num_partitions=num_partitions,
        replication_factor=replication_factor,
        topic_configs=topic_configs
    )
    try:
        admin_client.create_topics(new_topics=[new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully.")
    except TopicAlreadyExistsError:
        print(f"Warning: Topic '{topic_name}' already exists.")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def describe_topics(admin_client, topic_names):
    print(f"\nDescribing topics: {topic_names if topic_names else 'all'}")
    try:
        if topic_names:
            topic_metadata = admin_client.describe_topics(topic_names)
        else:
            # If no specific topics are given, list all topics
            topic_metadata = admin_client.describe_topics(admin_client.list_topics())

        for topic in topic_metadata:
            print(f"\nTopic: {topic.name}")
            print(f"  Partitions: {len(topic.partitions)}")
            print(f"  Is Internal: {topic.is_internal}")
            for partition in topic.partitions:
                print(f"    Partition {partition.id}: Leader={partition.leader.id}, Replicas={[r.id for r in partition.replicas]}, ISR={[isr.id for isr in partition.isr]}")
    except Exception as e:
        print(f"Error describing topics: {e}")

def describe_topic_configs(admin_client, topic_names):
    print(f"\nDescribing topic configurations for: {topic_names}")
    try:
        config_resources = [ConfigResource(ConfigResourceType.TOPIC, name) for name in topic_names]
        configs = admin_client.describe_configs(config_resources)
        for resource, config_entries in configs.items():
            print(f"\nTopic Configuration for '{resource.name}':")
            for entry in config_entries.values():
                print(f"  {entry.name}: {entry.value} (Source: {entry.source.name}, ReadOnly: {entry.read_only}, Sensitive: {entry.is_sensitive}, Default: {entry.is_default})")
    except UnknownTopicOrPartitionError as e:
        print(f"Error: One or more topics not found. {e}")
    except Exception as e:
        print(f"Error describing topic configurations: {e}")

def alter_topic_configs(admin_client, topic_name, config_updates):
    print(f"\nAttempting to alter configurations for topic: {topic_name}")
    print(f"  Updates: {config_updates}")

    config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
    try:
        admin_client.alter_configs({config_resource: config_updates})
        print(f"Configurations for topic '{topic_name}' altered successfully.")
    except UnknownTopicOrPartitionError:
        print(f"Error: Topic '{topic_name}' not found.")
    except Exception as e:
        print(f"Error altering topic configurations for '{topic_name}': {e}")

def delete_topics(admin_client, topic_names):
    print(f"\nAttempting to delete topics: {topic_names}")
    try:
        deleted_topics = admin_client.delete_topics(topic_names)
        for topic, error in deleted_topics.topics.items():
            if error:
                print(f"Error deleting topic '{topic}': {error}")
            else:
                print(f"Topic '{topic}' deleted successfully.")
    except UnknownTopicOrPartitionError:
        print(f"Warning: One or more topics to delete were not found.")
    except Exception as e:
        print(f"Error deleting topics: {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration Script using kafka-python AdminClient.")
    parser.add_argument('--bootstrap-servers', default='localhost:9092',
                        help='Comma-separated list of Kafka bootstrap servers.')
    parser.add_argument('--client-id', default='kafka-admin-script',
                        help='Client ID for the Kafka AdminClient.')

    subparsers = parser.add_subparsers(dest='command', required=True, help='Available commands')

    # Create Topic Command
    create_parser = subparsers.add_parser('create', help='Create a new Kafka topic.')
    create_parser.add_argument('--topic', required=True, help='Name of the topic to create.')
    create_parser.add_argument('--partitions', type=int, default=1,
                               help='Number of partitions for the new topic.')
    create_parser.add_argument('--replication-factor', type=int, default=1,
                               help='Replication factor for the new topic.')
    create_parser.add_argument('--config', nargs='*', default=[],
                               help='Topic configuration in key=value format (e.g., retention.ms=604800000).')

    # Describe Topics Command
    describe_parser = subparsers.add_parser('describe', help='Describe Kafka topics.')
    describe_parser.add_argument('--topic', nargs='*', default=None,
                                 help='Specific topic(s) to describe. If not provided, describes all topics.')

    # Describe Topic Configs Command
    describe_config_parser = subparsers.add_parser('describe-config', help='Describe Kafka topic configurations.')
    describe_config_parser.add_argument('--topic', nargs='+', required=True,
                                        help='Specific topic(s) for which to describe configurations.')

    # Alter Topic Configs Command
    alter_config_parser = subparsers.add_parser('alter-config', help='Alter configurations for an existing Kafka topic.')
    alter_config_parser.add_argument('--topic', required=True, help='Name of the topic to alter.')
    alter_config_parser.add_argument('--config', nargs='+', required=True,
                                     help='Topic configuration updates in key=value format (e.g., retention.ms=3600000).')

    # Delete Topics Command
    delete_parser = subparsers.add_parser('delete', help='Delete Kafka topic(s).')
    delete_parser.add_argument('--topic', nargs='+', required=True,
                               help='Specific topic(s) to delete.')

    args = parser.parse_args()

    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=args.bootstrap_servers,
            client_id=args.client_id
        )
        print(f"Connected to Kafka at: {args.bootstrap_servers}")
    except NoBrokersAvailable:
        print(f"Error: No Kafka brokers available at {args.bootstrap_servers}. Please check your connection.")
        exit(1)
    except Exception as e:
        print(f"Failed to connect to Kafka: {e}")
        exit(1)

    try:
        if args.command == 'create':
            topic_configs = {}
            for cfg in args.config:
                if '=' not in cfg:
                    print(f"Invalid config format: '{cfg}'. Expected key=value.")
                    exit(1)
                key, value = cfg.split('=', 1)
                topic_configs[key] = value
            create_topic(admin_client, args.topic, args.partitions, args.replication_factor, topic_configs)
        elif args.command == 'describe':
            describe_topics(admin_client, args.topic)
        elif args.command == 'describe-config':
            describe_topic_configs(admin_client, args.topic)
        elif args.command == 'alter-config':
            config_updates = {}
            for cfg in args.config:
                if '=' not in cfg:
                    print(f"Invalid config format: '{cfg}'. Expected key=value.")
                    exit(1)
                key, value = cfg.split('=', 1)
                config_updates[key] = value
            alter_topic_configs(admin_client, args.topic, config_updates)
        elif args.command == 'delete':
            delete_topics(admin_client, args.topic)
    finally:
        admin_client.close()
        print("KafkaAdminClient connection closed.")

if __name__ == '__main__':
    main()